4409 // Returns whether V is a Mask ((X + 1) & X == 0) or ~Mask (-Pow2OrZero)
4410 static bool isMaskOrZero(const Value *V, bool Not, const SimplifyQuery &Q,
4411                          unsigned Depth = 0) {
4412   if (Not ? match(V, m_NegatedPower2OrZero()) : match(V, m_LowBitMaskOrZero()))
4413     return true;
4414   if (V->getType()->getScalarSizeInBits() == 1)
4415     return true;
4416   if (Depth++ >= MaxAnalysisRecursionDepth)
4417     return false;
4418   Value *X;
4419   const Instruction *I = dyn_cast<Instruction>(V);
4420   if (!I)
4421     return false;
4422   switch (I->getOpcode()) {
4423   case Instruction::ZExt:
4424     // ZExt(Mask) is a Mask.
4425     return !Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4426   case Instruction::SExt:
4427     // SExt(Mask) is a Mask.
4428     // SExt(~Mask) is a ~Mask.
4429     return isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4430   case Instruction::And:
4431   case Instruction::Or:
4432     // Mask0 | Mask1 is a Mask.
4433     // Mask0 & Mask1 is a Mask.
4434     // ~Mask0 | ~Mask1 is a ~Mask.
4435     // ~Mask0 & ~Mask1 is a ~Mask.
4436     return isMaskOrZero(I->getOperand(1), Not, Q, Depth) &&
4437            isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4438   case Instruction::Xor:
4439     if (match(V, m_Not(m_Value(X))))
4440       return isMaskOrZero(X, !Not, Q, Depth);
4441 
4442     // (X ^ -X) is a ~Mask
4443     if (Not)
4444       return match(V, m_c_Xor(m_Value(X), m_Neg(m_Deferred(X))));
4445     // (X ^ (X - 1)) is a Mask
4446     else
4447       return match(V, m_c_Xor(m_Value(X), m_Add(m_Deferred(X), m_AllOnes())));
4448   case Instruction::Select:
4449     // c ? Mask0 : Mask1 is a Mask.
4450     return isMaskOrZero(I->getOperand(1), Not, Q, Depth) &&
4451            isMaskOrZero(I->getOperand(2), Not, Q, Depth);
4452   case Instruction::Shl:
4453     // (~Mask) << X is a ~Mask.
4454     return Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4455   case Instruction::LShr:
4456     // Mask >> X is a Mask.
4457     return !Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4458   case Instruction::AShr:
