4525     //  x & ~Mask == 0
4526     //  ~x | Mask == -1
4527     //    ->    x u<= Mask
4528     //  x & ~Mask == ~Mask
4529     //    ->    ~Mask u<= x
4530     DstPred = ICmpInst::Predicate::ICMP_ULE;
4531     break;
4532   case ICmpInst::Predicate::ICMP_NE:
4533     //  x & Mask != x
4534     //  x & ~Mask != 0
4535     //  ~x | Mask != -1
