5969 /// Offset both sides of an equality icmp to see if we can save some
5970 /// instructions: icmp eq/ne X, Y -> icmp eq/ne X op Z, Y op Z.
5971 /// Note: This operation should not introduce poison.
5972 static Instruction *foldICmpEqualityWithOffset(ICmpInst &I,
