5985     switch (BinOpc) {
5986     // V = shl nsw X, RHS => X = ashr V, RHS
5987     case Instruction::AShr: {
5988       const APInt *CV, *CRHS;
5989       if (!(match(V, m_APInt(CV)) && match(RHS, m_APInt(CRHS)) &&
