4423   case Instruction::ZExt:
4424     // ZExt(Mask) is a Mask.
4425     return !Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4426   case Instruction::SExt:
4427     // SExt(Mask) is a Mask.
4428     // SExt(~Mask) is a ~Mask.
4429     return isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4430   case Instruction::And:
4431   case Instruction::Or:
4432     // Mask0 | Mask1 is a Mask.
4433     // Mask0 & Mask1 is a Mask.
4434     // ~Mask0 | ~Mask1 is a ~Mask.
4435     // ~Mask0 & ~Mask1 is a ~Mask.
4436     return isMaskOrZero(I->getOperand(1), Not, Q, Depth) &&
4437            isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4438   case Instruction::Xor:
4439     if (match(V, m_Not(m_Value(X))))
