4449     // c ? Mask0 : Mask1 is a Mask.
4450     return isMaskOrZero(I->getOperand(1), Not, Q, Depth) &&
4451            isMaskOrZero(I->getOperand(2), Not, Q, Depth);
4452   case Instruction::Shl:
4453     // (~Mask) << X is a ~Mask.
4454     return Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4455   case Instruction::LShr:
4456     // Mask >> X is a Mask.
4457     return !Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
