4501 /// Some comparisons can be simplified.
4502 /// In this case, we are looking for comparisons that look like
4503 /// a check for a lossy truncation.
4504 /// Folds:
4505 ///   icmp SrcPred (x & Mask), x    to    icmp DstPred x, Mask
4506 ///   icmp SrcPred (x & ~Mask), ~Mask    to    icmp DstPred x, ~Mask
4507 ///   icmp eq/ne (x & ~Mask), 0     to    icmp DstPred x, Mask
4508 ///   icmp eq/ne (~x | Mask), -1     to    icmp DstPred x, Mask
4509 /// Where Mask is some pattern that produces all-ones in low bits:
4510 ///    (-1 >> y)
4511 ///    ((-1 << y) >> y)     <- non-canonical, has extra uses
4512 ///   ~(-1 << y)
4513 ///    ((1 << y) + (-1))    <- non-canonical, has extra uses
4514 /// The Mask can be a constant, too.
4515 /// For some predicates, the operands are commutative.
4516 /// For others, x can only be on a specific side.
4517 static Value *foldICmpWithLowBitMaskedVal(CmpPredicate Pred, Value *Op0,
4518                                           Value *Op1, const SimplifyQuery &Q,
4519                                           InstCombiner &IC) {
4520 
4521   ICmpInst::Predicate DstPred;
4522   switch (Pred) {
4523   case ICmpInst::Predicate::ICMP_EQ:
4524     //  x & Mask == x
4525     //  x & ~Mask == 0
4526     //  ~x | Mask == -1
4527     //    ->    x u<= Mask
4528     //  x & ~Mask == ~Mask
4529     //    ->    ~Mask u<= x
4530     DstPred = ICmpInst::Predicate::ICMP_ULE;
4531     break;
4532   case ICmpInst::Predicate::ICMP_NE:
4533     //  x & Mask != x
4534     //  x & ~Mask != 0
4535     //  ~x | Mask != -1
4536     //    ->    x u> Mask
4537     //  x & ~Mask != ~Mask
4538     //    ->    ~Mask u> x
4539     DstPred = ICmpInst::Predicate::ICMP_UGT;
4540     break;
4541   case ICmpInst::Predicate::ICMP_ULT:
4542     //  x & Mask u< x
4543     //    -> x u> Mask
4544     //  x & ~Mask u< ~Mask
4545     //    -> ~Mask u> x
4546     DstPred = ICmpInst::Predicate::ICMP_UGT;
4547     break;
4548   case ICmpInst::Predicate::ICMP_UGE:
4549     //  x & Mask u>= x
4550     //    -> x u<= Mask
4551     //  x & ~Mask u>= ~Mask
4552     //    -> ~Mask u<= x
4553     DstPred = ICmpInst::Predicate::ICMP_ULE;
4554     break;
4555   case ICmpInst::Predicate::ICMP_SLT:
4556     //  x & Mask s< x [iff Mask s>= 0]
4557     //    -> x s> Mask
4558     //  x & ~Mask s< ~Mask [iff ~Mask != 0]
4559     //    -> ~Mask s> x
4560     DstPred = ICmpInst::Predicate::ICMP_SGT;
4561     break;
4562   case ICmpInst::Predicate::ICMP_SGE:
4563     //  x & Mask s>= x [iff Mask s>= 0]
4564     //    -> x s<= Mask
4565     //  x & ~Mask s>= ~Mask [iff ~Mask != 0]
4566     //    -> ~Mask s<= x
4567     DstPred = ICmpInst::Predicate::ICMP_SLE;
4568     break;
4569   default:
4570     // We don't support sgt,sle
4571     // ult/ugt are simplified to true/false respectively.
4572     return nullptr;
4573   }
4574 
4575   Value *X, *M;
4576   // Put search code in lambda for early positive returns.
4577   auto IsLowBitMask = [&]() {
4578     if (match(Op0, m_c_And(m_Specific(Op1), m_Value(M)))) {
4579       X = Op1;
4580       // Look for: x & Mask pred x
4581       if (isMaskOrZero(M, /*Not=*/false, Q)) {
4582         return !ICmpInst::isSigned(Pred) ||
4583                (match(M, m_NonNegative()) || isKnownNonNegative(M, Q));
4584       }
4585 
4586       // Look for: x & ~Mask pred ~Mask
4587       if (isMaskOrZero(X, /*Not=*/true, Q)) {
4588         return !ICmpInst::isSigned(Pred) || isKnownNonZero(X, Q);
4589       }
4590       return false;
4591     }
4592     if (ICmpInst::isEquality(Pred) && match(Op1, m_AllOnes()) &&
4593         match(Op0, m_OneUse(m_Or(m_Value(X), m_Value(M))))) {
4594 
4595       auto Check = [&]() {
4596         // Look for: ~x | Mask == -1
4597         if (isMaskOrZero(M, /*Not=*/false, Q)) {
4598           if (Value *NotX =
4599                   IC.getFreelyInverted(X, X->hasOneUse(), &IC.Builder)) {
4600             X = NotX;
4601             return true;
4602           }
4603         }
4604         return false;
4605       };
4606       if (Check())
4607         return true;
4608       std::swap(X, M);
4609       return Check();
4610     }
4611     if (ICmpInst::isEquality(Pred) && match(Op1, m_Zero()) &&
4612         match(Op0, m_OneUse(m_And(m_Value(X), m_Value(M))))) {
4613       auto Check = [&]() {
4614         // Look for: x & ~Mask == 0
4615         if (isMaskOrZero(M, /*Not=*/true, Q)) {
4616           if (Value *NotM =
4617                   IC.getFreelyInverted(M, M->hasOneUse(), &IC.Builder)) {
4618             M = NotM;
4619             return true;
4620           }
4621         }
4622         return false;
4623       };
4624       if (Check())
4625         return true;
4626       std::swap(X, M);
4627       return Check();
4628     }
4629     return false;
4630   };
4631 
4632   if (!IsLowBitMask())
4633     return nullptr;
4634 
